  function clean(s) {
    return s.replace(/&amp;amp;amp;/gi,'&').replace(/&amp;amp;/gi,'&')
            .replace(/&amp;/gi,'&').replace(/&AMP;/gi,'&')
            .replace(/\s+/g,' ').trim();
  }
